#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
ll x, y, a, b, n, m, l;
ll exgcd (ll a, ll b, ll &x, ll &y) {
    return !b ? (x = 1, y = 0, a) : (exgcd (b, a % b, y, x), y -= (a / b) * x);
}
ll mul (ll a, ll b, ll mod) {
    ll ret = 0;
    while (b) {
        if (b & 1) {
    	    ret = (ret + a) % mod;
	    }
        a = (a + a) % mod;
        b >>= 1;
    }
    return ret % mod;
}
ll Pow (ll a, ll b, ll mod) {
    ll ret = 1;
    while (b) {
        if (b & 1) {
		    ret = mul (ret, a, mod);
	    }
        a = mul (a, a, mod);
        b >>= 1;
    }
    return ret % mod;
}
int main() {
    cin >> n >> m >> l;
    exgcd (2, n + 1, x, y);
    x = (x % (n + 1) + n + 1) % (n + 1);
    x = Pow(x, m, n + 1);
    cout << mul(l, x, n + 1);
    return 0;
}
